# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
import statsmodels.api as sm
from sklearn.model_selection import KFold
from typing import Dict, List

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# Import analysis and validation tools
from tools.analysis_regression import cross_validate_regression
from tools.validation import validate_numeric_range

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]
LOG_FILE = RQ_DIR / "logs" / "step04_cross_validation.log"
OUTPUT_DIR = RQ_DIR / "data"

# Ensure output directory exists
OUTPUT_DIR.mkdir(parents=True, exist_ok=True)

# CV parameters
N_FOLDS = 5
RANDOM_STATE = 42
N_BOOTSTRAP = 1000
OVERFITTING_THRESHOLD = 0.10  # Shrinkage > 10% indicates overfitting

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Helper Functions
# =============================================================================

def stratified_kfold_by_age(df: pd.DataFrame, n_splits: int = 5, random_state: int = 42):
    """
    Create stratified K-fold splits by age tertiles.
    Ensures balanced age distribution across folds.
    """
    # Create age tertiles
    df['age_tertile'] = pd.qcut(df['Age'], q=3, labels=['Young', 'Middle', 'Older'])

    # Use sklearn KFold on indices, manually ensuring stratification
    np.random.seed(random_state)
    indices = np.arange(len(df))

    # Group by tertile
    tertile_groups = df.groupby('age_tertile').groups

    # Generate folds maintaining tertile proportions
    folds = [[] for _ in range(n_splits)]

    for tertile, group_indices in tertile_groups.items():
        group_indices = np.array(group_indices)
        np.random.shuffle(group_indices)

        # Split into n_splits parts
        fold_size = len(group_indices) // n_splits
        for i in range(n_splits):
            start_idx = i * fold_size
            end_idx = (i + 1) * fold_size if i < n_splits - 1 else len(group_indices)
            folds[i].extend(group_indices[start_idx:end_idx].tolist())

    # Convert to train/test splits
    for i in range(n_splits):
        test_indices = folds[i]
        train_indices = [idx for j in range(n_splits) if j != i for idx in folds[j]]
        yield train_indices, test_indices

def fit_and_evaluate_model(X_train, y_train, X_test, y_test):
    """
    Fit OLS model and compute R² on train and test sets.
    """
    # Add constant
    X_train_const = sm.add_constant(X_train, has_constant='add')
    X_test_const = sm.add_constant(X_test, has_constant='add')

    # Fit model
    model = sm.OLS(y_train, X_train_const).fit()

    # Train R²
    train_r2 = model.rsquared

    # Test R² (manual computation)
    y_pred = model.predict(X_test_const)
    ss_res = np.sum((y_test - y_pred) ** 2)
    ss_tot = np.sum((y_test - np.mean(y_test)) ** 2)
    test_r2 = 1 - (ss_res / ss_tot) if ss_tot > 0 else 0.0

    return train_r2, test_r2

def bootstrap_cv_r2(X, y, predictor_cols, n_folds=5, n_bootstrap=1000, random_state=42):
    """
    Bootstrap confidence intervals for CV-R² using simple K-fold (not stratified).
    Stratification causes indexing issues in bootstrap, use simpler approach for CIs.
    """
    np.random.seed(random_state)
    cv_r2_dist = []

    for i in range(n_bootstrap):
        # Bootstrap sample
        boot_indices = np.random.choice(len(X), size=len(X), replace=True)
        X_boot = X.iloc[boot_indices][predictor_cols].values
        y_boot = y.iloc[boot_indices].values

        # Perform simple K-fold CV on bootstrap sample (no stratification to avoid indexing issues)
        kf = KFold(n_splits=n_folds, shuffle=True, random_state=i)
        fold_r2s = []

        for train_idx, test_idx in kf.split(X_boot):
            X_train, X_test = X_boot[train_idx], X_boot[test_idx]
            y_train, y_test = y_boot[train_idx], y_boot[test_idx]

            _, test_r2 = fit_and_evaluate_model(X_train, y_train, X_test, y_test)
            fold_r2s.append(test_r2)

        cv_r2_dist.append(np.mean(fold_r2s))

    # Compute 95% CI (percentile method)
    ci_lower = np.percentile(cv_r2_dist, 2.5)
    ci_upper = np.percentile(cv_r2_dist, 97.5)

    return ci_lower, ci_upper

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 04: Cross-Validation")

        # =========================================================================
        # STEP 1: Load Data
        # =========================================================================
        log("[LOAD] Loading analysis dataset and model specifications...")

        analysis_file = RQ_DIR / 'data' / 'step02_analysis_input.csv'
        df_analysis = pd.read_csv(analysis_file)
        log(f"[LOADED] Analysis dataset: {len(df_analysis)} rows")

        models_file = RQ_DIR / 'data' / 'step03_nested_models.csv'
        df_models = pd.read_csv(models_file)
        log(f"[LOADED] Model specifications: {len(df_models)} models")

        # Outcome variable
        y = df_analysis['Theta_All']
        log(f"[INFO] Outcome (Theta_All): mean={y.mean():.3f}, SD={y.std():.3f}")

        # =========================================================================
        # STEP 2: Perform Cross-Validation for Each Model
        # =========================================================================
        log(f"[CV] Performing {N_FOLDS}-fold cross-validation for {len(df_models)} models...")

        cv_results = []
        fold_details = []

        for _, model_row in df_models.iterrows():
            model_name = model_row['model_name']
            predictor_list = [p.strip() for p in model_row['predictor_list'].split(',')]

            log(f"\n[MODEL] {model_name} ({len(predictor_list)} predictors)")
            log(f"[INFO] Predictors: {predictor_list}")

            # Extract predictors
            X = df_analysis[predictor_list]

            # Perform stratified CV
            train_r2s = []
            cv_r2s = []

            fold_num = 1
            for train_idx, test_idx in stratified_kfold_by_age(df_analysis, n_splits=N_FOLDS, random_state=RANDOM_STATE):
                X_train = X.iloc[train_idx].values
                X_test = X.iloc[test_idx].values
                y_train = y.iloc[train_idx].values
                y_test = y.iloc[test_idx].values

                train_r2, test_r2 = fit_and_evaluate_model(X_train, y_train, X_test, y_test)

                train_r2s.append(train_r2)
                cv_r2s.append(test_r2)

                shrinkage = train_r2 - test_r2
                log(f"  Fold {fold_num}: Train R²={train_r2:.4f}, CV R²={test_r2:.4f}, Shrinkage={shrinkage:.4f}")

                fold_details.append({
                    'model': model_name,
                    'fold': fold_num,
                    'train_r2': train_r2,
                    'cv_r2': test_r2,
                    'shrinkage': shrinkage
                })

                fold_num += 1

            # Aggregate results
            train_r2_mean = np.mean(train_r2s)
            train_r2_sd = np.std(train_r2s, ddof=1)
            cv_r2_mean = np.mean(cv_r2s)
            cv_r2_sd = np.std(cv_r2s, ddof=1)
            shrinkage_mean = train_r2_mean - cv_r2_mean
            overfitting_flag = shrinkage_mean > OVERFITTING_THRESHOLD

            log(f"[SUMMARY] Train R²: {train_r2_mean:.4f} ± {train_r2_sd:.4f}")
            log(f"[SUMMARY] CV R²: {cv_r2_mean:.4f} ± {cv_r2_sd:.4f}")
            log(f"[SUMMARY] Shrinkage: {shrinkage_mean:.4f}")
            log(f"[SUMMARY] Overfitting: {'YES' if overfitting_flag else 'NO'}")

            cv_results.append({
                'model': model_name,
                'train_r2_mean': train_r2_mean,
                'train_r2_sd': train_r2_sd,
                'cv_r2_mean': cv_r2_mean,
                'cv_r2_sd': cv_r2_sd,
                'shrinkage': shrinkage_mean,
                'overfitting_flag': overfitting_flag
            })

        # =========================================================================
        # STEP 3: Bootstrap Confidence Intervals
        # =========================================================================
        log(f"\n[BOOTSTRAP] Computing {N_BOOTSTRAP} bootstrap CIs for CV-R²...")

        bootstrap_results = []

        for _, model_row in df_models.iterrows():
            model_name = model_row['model_name']
            predictor_list = [p.strip() for p in model_row['predictor_list'].split(',')]

            log(f"[BOOTSTRAP] {model_name}...")

            X = df_analysis[predictor_list + ['Age']]  # Include Age for stratification
            ci_lower, ci_upper = bootstrap_cv_r2(
                X, y, predictor_list,
                n_folds=N_FOLDS,
                n_bootstrap=N_BOOTSTRAP,
                random_state=RANDOM_STATE
            )

            # Get CV-R² mean from previous step
            cv_r2_mean = [r['cv_r2_mean'] for r in cv_results if r['model'] == model_name][0]

            log(f"[CI] CV-R²={cv_r2_mean:.4f}, 95% CI=[{ci_lower:.4f}, {ci_upper:.4f}]")

            bootstrap_results.append({
                'model': model_name,
                'cv_r2_mean': cv_r2_mean,
                'ci_lower': ci_lower,
                'ci_upper': ci_upper
            })

        # =========================================================================
        # STEP 4: Save Outputs
        # =========================================================================
        log("\n[SAVE] Saving cross-validation results...")

        # CV summary
        df_cv = pd.DataFrame(cv_results)
        cv_file = OUTPUT_DIR / "step04_cv_results.csv"
        df_cv.to_csv(cv_file, index=False, encoding='utf-8')
        log(f"[SAVED] CV results: {cv_file}")

        # Bootstrap CIs
        df_bootstrap = pd.DataFrame(bootstrap_results)
        bootstrap_file = OUTPUT_DIR / "step04_cv_bootstrap_cis.csv"
        df_bootstrap.to_csv(bootstrap_file, index=False, encoding='utf-8')
        log(f"[SAVED] Bootstrap CIs: {bootstrap_file}")

        # Fold details
        df_folds = pd.DataFrame(fold_details)
        folds_file = OUTPUT_DIR / "step04_fold_details.csv"
        df_folds.to_csv(folds_file, index=False, encoding='utf-8')
        log(f"[SAVED] Fold details: {folds_file}")

        # =========================================================================
        # STEP 5: Validation Checks
        # =========================================================================
        log("\n[VALIDATION] Validating CV results...")

        # Check CV-R² range
        for result in cv_results:
            model_name = result['model']
            cv_r2 = result['cv_r2_mean']

            if 0 <= cv_r2 <= 1:
                log(f"[PASS] {model_name}: CV-R²={cv_r2:.4f} in valid range [0, 1]")
            else:
                log(f"[ERROR] {model_name}: CV-R²={cv_r2:.4f} outside valid range [0, 1]")

        # Check shrinkage >= 0
        for result in cv_results:
            model_name = result['model']
            shrinkage = result['shrinkage']

            if shrinkage >= 0:
                log(f"[PASS] {model_name}: Shrinkage={shrinkage:.4f} >= 0")
            else:
                log(f"[WARNING] {model_name}: Negative shrinkage={shrinkage:.4f} (CV R² > Train R²)")

        log("[SUCCESS] Step 04 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        import traceback
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
